    ('RU000A10ELF6', DATE '2026-03-28', 100),
    ('RU000A10ELF6', DATE '2026-03-29', 99.76)
),
resolved AS (
    SELECT
        i.id AS instrument_id,
        s.trade_date,
        s.price::numeric(18,4) AS price,
        i.currency_id,
        md5(i.id::text || '|' || s.trade_date::text || '|TBANK') AS hash_key
    FROM src s
    JOIN instruments i
      ON upper(coalesce(i.figi, '')) = s.db_code
      OR upper(i.ticker) = s.db_code
)
INSERT INTO prices (id, instrument_id, date, value, currency_id, provider, created_at, updated_at)
SELECT
    (
        substr(hash_key, 1, 8) || '-' ||
        substr(hash_key, 9, 4) || '-' ||
        substr(hash_key, 13, 4) || '-' ||
        substr(hash_key, 17, 4) || '-' ||
        substr(hash_key, 21, 12)
    )::uuid,
    instrument_id,
    (trade_date::timestamp AT TIME ZONE 'UTC'),
    price,
    currency_id,
    'TBANK',
    now(),
    now()
FROM resolved
ON CONFLICT (instrument_id, date, provider)
DO UPDATE
SET value = EXCLUDED.value,
    currency_id = EXCLUDED.currency_id,
    updated_at = now();

COMMIT;

-- Source: scripts/moex_history/sql/report_2026_mts_2p17.sql (TBANK price rows only)

BEGIN;

WITH instrument_ref AS (
    SELECT id
    FROM instruments
    WHERE ticker = 'RU000A10ELF6'
),
price_rows AS (
    SELECT * FROM (
        VALUES
            ('2026-03-18'::date, 997.9000::numeric, 'RUB'::varchar),
            ('2026-03-19'::date, 998.4700::numeric, 'RUB'::varchar),
            ('2026-03-20'::date, 999.3400::numeric, 'RUB'::varchar)
    ) AS v(price_date, value, currency_id)
)
INSERT INTO prices (
    id,
    instrument_id,
    date,
    value,
    currency_id,
    provider,
    created_at,
    updated_at,
    source_currency_id
)
SELECT
    gen_random_uuid(),
    instrument_ref.id,
    price_rows.price_date::timestamp AT TIME ZONE 'UTC',
    price_rows.value,
    price_rows.currency_id,
    'TBANK',
    now(),
    now(),
    NULL
FROM instrument_ref
CROSS JOIN price_rows
ON CONFLICT (instrument_id, date, provider)
DO UPDATE
SET value = EXCLUDED.value,
    currency_id = EXCLUDED.currency_id,
    updated_at = now(),
    source_currency_id = EXCLUDED.source_currency_id;

COMMIT;
